/**
 * 本地 HTTP + WebSocket 服务器，用于远程控制台（与 xw 2.3.0 一致）
 */
import * as http from "node:http";
import * as crypto from "node:crypto";
import { getConsoleHtml } from "./console-html";

const WS_MAGIC = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";

export interface ConsoleState {
  queueCount: number;
  queue: unknown[];
  question: unknown;
  reply: unknown;
  progress: unknown;
  workspace: { name: string; path?: string };
  wsClients: number;
  port: number;
}

export interface ConsoleHandlers {
  sendText: (text: string) => void;
  writeAnswer: (data: unknown) => void;
  cancelQuestion: () => void;
  clearReply: () => void;
}

let server: http.Server | null = null;
let wsClients: { socket: import("node:net").Socket; alive: boolean }[] = [];
let serverPort = 0;
let pollTimer: ReturnType<typeof setInterval> | null = null;
let lastPushState = "";
let workspaceInfo: { name: string; path?: string } = { name: "", path: "" };

let getState: () => ConsoleState = () => ({
  queueCount: 0,
  queue: [],
  question: null,
  reply: null,
  progress: null,
  workspace: workspaceInfo,
  wsClients: 0,
  port: serverPort,
});
let handlers: ConsoleHandlers | null = null;

export function setWorkspaceInfo(name: string, path?: string): void {
  workspaceInfo = { name, path };
}

export function getServerPort(): number {
  return serverPort;
}

export function getConnectedClients(): number {
  return wsClients.length;
}

function buildPushState(): ConsoleState {
  const s = getState();
  return { ...s, workspace: workspaceInfo, wsClients: wsClients.length, port: serverPort };
}

function broadcast(data: object): void {
  const msg = JSON.stringify(data);
  wsClients.forEach((c) => {
    try {
      wsSend(c.socket, msg);
    } catch {
      // ignore
    }
  });
}

function wsSendRaw(socket: import("node:net").Socket, buf: Buffer): void {
  try {
    socket.write(buf);
  } catch {
    // ignore
  }
}

function buildFrame(payload: string | Buffer, opcode = 1): Buffer {
  const data = typeof payload === "string" ? Buffer.from(payload, "utf-8") : payload;
  const len = data.length;
  let header: Buffer;
  if (len < 126) {
    header = Buffer.alloc(2);
    header[0] = 0x80 | opcode;
    header[1] = len;
  } else if (len < 65536) {
    header = Buffer.alloc(4);
    header[0] = 0x80 | opcode;
    header[1] = 126;
    header.writeUInt16BE(len, 2);
  } else {
    header = Buffer.alloc(10);
    header[0] = 0x80 | opcode;
    header[1] = 127;
    header.writeBigUInt64BE(BigInt(len), 2);
  }
  return Buffer.concat([header, data]);
}

function wsSend(socket: import("node:net").Socket, msg: string): void {
  wsSendRaw(socket, buildFrame(msg));
}

function removeClient(client: { socket: import("node:net").Socket }): void {
  const idx = wsClients.indexOf(client as (typeof wsClients)[0]);
  if (idx !== -1) wsClients.splice(idx, 1);
  try {
    client.socket.destroy();
  } catch {
    // ignore
  }
}

function handleWsMessage(_client: unknown, raw: string): void {
  if (!handlers) return;
  try {
    const msg = JSON.parse(raw) as { type: string; text?: string; data?: unknown };
    switch (msg.type) {
      case "sendText":
        if (msg.text) {
          handlers.sendText(msg.text);
          broadcast({ type: "queueUpdate", count: buildPushState().queueCount });
        }
        break;
      case "submitAnswer":
        if (msg.data) handlers.writeAnswer(msg.data);
        break;
      case "cancelQuestion":
        handlers.cancelQuestion();
        break;
      case "ackReply":
        handlers.clearReply();
        break;
    }
  } catch {
    // ignore
  }
}

function parseFrame(buf: Buffer): { opcode: number; payload: Buffer; totalLength: number } | null {
  if (buf.length < 2) return null;
  const opcode = buf[0] & 0x0f;
  const masked = (buf[1] & 0x80) !== 0;
  let payloadLen = buf[1] & 0x7f;
  let offset = 2;
  if (payloadLen === 126) {
    if (buf.length < 4) return null;
    payloadLen = buf.readUInt16BE(2);
    offset = 4;
  } else if (payloadLen === 127) {
    if (buf.length < 10) return null;
    payloadLen = Number(buf.readBigUInt64BE(2));
    offset = 10;
  }
  const maskLen = masked ? 4 : 0;
  const totalLength = offset + maskLen + payloadLen;
  if (buf.length < totalLength) return null;
  let payload = buf.subarray(offset + maskLen, offset + maskLen + payloadLen);
  if (masked) {
    const mask = buf.subarray(offset, offset + 4);
    payload = Buffer.from(payload);
    for (let i = 0; i < payload.length; i++) payload[i] ^= mask[i % 4];
  }
  return { opcode, payload, totalLength };
}

function handleUpgrade(req: http.IncomingMessage, socket: import("node:net").Socket): void {
  const key = req.headers["sec-websocket-key"];
  if (!key) {
    socket.destroy();
    return;
  }
  const accept = crypto.createHash("sha1").update(key + WS_MAGIC).digest("base64");
  socket.write(
    "HTTP/1.1 101 Switching Protocols\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Accept: " +
      accept +
      "\r\n\r\n"
  );
  const client = { socket, alive: true };
  wsClients.push(client);
  const pushState = buildPushState();
  wsSend(socket, JSON.stringify({ type: "init", ...pushState }));
  let buffer = Buffer.alloc(0);
  socket.on("data", (chunk: Buffer) => {
    buffer = Buffer.concat([buffer, chunk]);
    while (buffer.length >= 2) {
      const parsed = parseFrame(buffer);
      if (!parsed) break;
      buffer = buffer.subarray(parsed.totalLength);
      if (parsed.opcode === 8) {
        removeClient(client);
        socket.end();
        return;
      }
      if (parsed.opcode === 9) {
        wsSendRaw(socket, buildFrame(parsed.payload, 10));
        continue;
      }
      if (parsed.opcode === 10) {
        client.alive = true;
        continue;
      }
      if (parsed.opcode === 1) {
        handleWsMessage(client, parsed.payload.toString("utf-8"));
      }
    }
  });
  socket.on("close", () => removeClient(client));
  socket.on("error", () => removeClient(client));
}

function handleHttp(req: http.IncomingMessage, res: http.ServerResponse): void {
  res.setHeader("Access-Control-Allow-Origin", "*");
  res.setHeader("Access-Control-Allow-Methods", "GET, POST, OPTIONS");
  res.setHeader("Access-Control-Allow-Headers", "Content-Type");
  if (req.method === "OPTIONS") {
    res.writeHead(204);
    res.end();
    return;
  }
  const url = req.url ?? "";
  if (url === "/" || url === "/index.html") {
    res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
    res.end(getConsoleHtml());
    return;
  }
  if (url === "/api/status" && req.method === "GET") {
    const state = buildPushState();
    res.writeHead(200, { "Content-Type": "application/json" });
    res.end(JSON.stringify(state));
    return;
  }
  if (url === "/api/send" && req.method === "POST") {
    let body = "";
    req.on("data", (chunk: Buffer) => {
      body += chunk.toString();
    });
    req.on("end", () => {
      try {
        const data = JSON.parse(body) as { text?: string };
        if (data.text && handlers) {
          handlers.sendText(data.text);
          res.writeHead(200, { "Content-Type": "application/json" });
          res.end(JSON.stringify({ success: true }));
          broadcast({ type: "queueUpdate", count: buildPushState().queueCount });
        } else {
          res.writeHead(400, { "Content-Type": "application/json" });
          res.end(JSON.stringify({ success: false, error: "缺少 text 字段" }));
        }
      } catch {
        res.writeHead(400, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ success: false, error: "无效的 JSON" }));
      }
    });
    return;
  }
  res.writeHead(404);
  res.end("Not Found");
}

function startPushPolling(): void {
  if (pollTimer) return;
  pollTimer = setInterval(() => {
    if (wsClients.length === 0) return;
    const state = JSON.stringify(buildPushState());
    if (state !== lastPushState) {
      lastPushState = state;
      broadcast({ type: "stateUpdate", ...JSON.parse(state) });
    }
  }, 500);
}

export function startLocalServer(
  getStateFn: () => ConsoleState,
  handlersFn: ConsoleHandlers,
  port = 0
): Promise<number> {
  getState = getStateFn;
  handlers = handlersFn;
  return new Promise((resolve, reject) => {
    if (server) {
      resolve(serverPort);
      return;
    }
    server = http.createServer(handleHttp);
    server.on("upgrade", (req, socket) => handleUpgrade(req, socket));
    server.on("error", reject);
    server.listen(port, "0.0.0.0", () => {
      const addr = server!.address();
      serverPort = typeof addr === "object" && addr ? addr.port : 0;
      startPushPolling();
      resolve(serverPort);
    });
  });
}

export function stopLocalServer(): void {
  if (pollTimer) {
    clearInterval(pollTimer);
    pollTimer = null;
  }
  wsClients.forEach((c) => {
    try {
      c.socket.destroy();
    } catch {
      // ignore
    }
  });
  wsClients = [];
  if (server) {
    server.close();
    server = null;
    serverPort = 0;
  }
}
