/**
 * File IPC layer: queue, question, answer, reply.
 * 支持多窗口：通过 setDataDir 按工作区切换数据目录，与 xw 2.0.7 一致。
 */
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";

const ROOT_DATA_DIR = path.join(os.homedir(), ".cursor-mcp-messenger");

let currentDataDir: string | null = null;

/** 当前使用的数据目录（按工作区隔离时由 extension 设置）。 */
export function getDataDir(): string {
  return currentDataDir ?? process.env.MESSENGER_DATA_DIR ?? ROOT_DATA_DIR;
}

/** 设置当前工作区对应的数据目录，多窗口时每个窗口使用独立目录。 */
export function setDataDir(dir: string): void {
  currentDataDir = dir;
}

function queueFile(): string {
  return path.join(getDataDir(), "queue.json");
}
function questionFile(): string {
  return path.join(getDataDir(), "question.json");
}
function answerFile(): string {
  return path.join(getDataDir(), "answer.json");
}
function replyFile(): string {
  return path.join(getDataDir(), "reply.json");
}
function progressFile(): string {
  return path.join(getDataDir(), "progress.json");
}

export interface QueueItem {
  id: string;
  type: "text" | "image" | "file";
  content?: string;
  path?: string;
  caption?: string;
  suffix?: string;
  timestamp: string;
  /** 会话 ID：有则仅被对应 session 的 check_messages 消费，避免同工作区多会话串消息。 */
  session_id?: string;
}

export interface QuestionItem {
  id: string;
  question: string;
  options: Array<{ id: string; label: string }>;
  allow_multiple: boolean;
}

export interface QuestionData {
  id: string;
  questions: QuestionItem[];
  timestamp: string;
}

export interface AnswerData {
  id: string;
  answers: Array<{ questionId: string; selected: string[]; other?: string }>;
}

export interface ReplyData {
  content: string;
  timestamp: string;
}

function ensureDir(): void {
  const dir = getDataDir();
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
}

export function makeId(): string {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 8);
}

export function readQueue(sessionId?: string | null): QueueItem[] {
  ensureDir();
  const file = queueFile();
  if (!fs.existsSync(file)) return [];
  try {
    const data = JSON.parse(fs.readFileSync(file, "utf-8"));
    const list = Array.isArray(data) ? data : [];
    if (sessionId == null || sessionId === "") return list;
    return list.filter((item: QueueItem) => item.session_id == null || item.session_id === sessionId);
  } catch {
    return [];
  }
}

export function writeQueue(items: QueueItem[]): void {
  ensureDir();
  fs.writeFileSync(queueFile(), JSON.stringify(items, null, 2), "utf-8");
}

/** 从 current_session.json 读取当前会话标识（由 MCP register_session 写入 session_tag），无则返回 null。兼容旧版 session_id。 */
export function getCurrentSessionId(): string | null {
  const file = path.join(getDataDir(), "current_session.json");
  if (!fs.existsSync(file)) return null;
  try {
    const data = JSON.parse(fs.readFileSync(file, "utf-8")) as { session_tag?: string; session_id?: string };
    const tag = data?.session_tag ?? data?.session_id;
    return typeof tag === "string" ? tag : null;
  } catch {
    return null;
  }
}

export function sendText(text: string, sessionId?: string | null): void {
  const queue = readQueue();
  const item: QueueItem = {
    id: makeId(),
    type: "text",
    content: text,
    timestamp: new Date().toISOString(),
  };
  if (sessionId) item.session_id = sessionId;
  queue.push(item);
  writeQueue(queue);
}

export function sendImage(filePath: string, caption?: string, sessionId?: string | null): void {
  const queue = readQueue();
  const item: QueueItem = {
    id: makeId(),
    type: "image",
    path: filePath,
    caption,
    timestamp: new Date().toISOString(),
  };
  if (sessionId) item.session_id = sessionId;
  queue.push(item);
  writeQueue(queue);
}

export function sendFile(filePath: string, suffix?: string, sessionId?: string | null): void {
  const queue = readQueue();
  const item: QueueItem = {
    id: makeId(),
    type: "file",
    path: filePath,
    suffix,
    timestamp: new Date().toISOString(),
  };
  if (sessionId) item.session_id = sessionId;
  queue.push(item);
  writeQueue(queue);
}

export function getQueueCount(sessionId?: string | null): number {
  return readQueue(sessionId).length;
}

export function deleteQueueItem(id: string): void {
  const queue = readQueue().filter((item) => item.id !== id);
  writeQueue(queue);
}

export function readQuestion(): QuestionData | null {
  const file = questionFile();
  if (!fs.existsSync(file)) return null;
  try {
    const data = JSON.parse(fs.readFileSync(file, "utf-8"));
    return data?.id && data?.questions ? data : null;
  } catch {
    return null;
  }
}

export function writeAnswer(answer: AnswerData): void {
  ensureDir();
  fs.writeFileSync(answerFile(), JSON.stringify(answer, null, 2), "utf-8");
}

export function cancelQuestion(): void {
  const q = readQuestion();
  if (!q) return;
  const answers = q.questions.map((qi, i) => ({
    questionId: qi.id,
    selected: [] as string[],
    other: i === 0 ? "用户取消了回答" : "",
  }));
  writeAnswer({ id: q.id, answers });
}

export function readReply(): ReplyData | null {
  const file = replyFile();
  if (!fs.existsSync(file)) return null;
  try {
    const data = JSON.parse(fs.readFileSync(file, "utf-8"));
    return data?.content != null ? data : null;
  } catch {
    return null;
  }
}

export function clearReply(): void {
  try {
    fs.unlinkSync(replyFile());
  } catch {
    // ignore
  }
}

export interface ProgressData {
  content: string;
  timestamp: string;
}

export function readProgress(): ProgressData | null {
  const file = progressFile();
  if (!fs.existsSync(file)) return null;
  try {
    const data = JSON.parse(fs.readFileSync(file, "utf-8"));
    return data?.content != null ? data : null;
  } catch {
    return null;
  }
}
