/**
 * Cursor Messenger extension: Webview panel, file IPC, MCP config & rules.
 * 支持多窗口：按首工作区路径 hash 隔离数据目录，与 xw 2.0.7 一致。
 */
import * as vscode from "vscode";
import * as path from "node:path";
import * as fs from "node:fs";
import * as os from "node:os";
import * as crypto from "node:crypto";
import {
  readQueue,
  sendText,
  sendImage,
  sendFile,
  getQueueCount,
  getCurrentSessionId,
  deleteQueueItem,
  readQuestion,
  writeAnswer,
  cancelQuestion,
  readReply,
  clearReply,
  readProgress,
  makeId,
  setDataDir,
  getDataDir,
  type AnswerData,
} from "./messenger";
import {
  startLocalServer,
  stopLocalServer,
  getServerPort,
  setWorkspaceInfo,
  getConnectedClients,
} from "./local-server";
import {
  RULES_CONTENT,
  RULES_FILE_NAME,
  LEGACY_RULES_FILE_NAME,
} from "./rules";
import { fetchCursorUsage } from "./cursor-usage";

const MCP_DISPLAY_NAME = "Cursor Messenger";
const ROOT_DATA_DIR = path.join(os.homedir(), ".cursor-mcp-messenger");

/** 用于持久化 webview 输入与历史的 globalState 键 */
const WEBVIEW_STATE_KEY = "messengerWebviewState";

/** 全局配置目录，Win/Mac 通用（os.homedir() 在 Win 为 %USERPROFILE%，Mac 为 /Users/xxx）。 */
const GLOBAL_CURSOR_DIR = path.join(os.homedir(), ".cursor");
const GLOBAL_MCP_JSON = path.join(GLOBAL_CURSOR_DIR, "mcp.json");
const GLOBAL_RULES_DIR = path.join(GLOBAL_CURSOR_DIR, "rules");

/** 按首工作区路径计算数据目录，多窗口/多工作区互不干扰（与 xw 2.0.7 一致）。 */
function computeDataDir(workspaceFolders: readonly vscode.WorkspaceFolder[]): string {
  if (workspaceFolders.length === 0) return ROOT_DATA_DIR;
  const primary = workspaceFolders[0].uri.fsPath;
  const hash = crypto.createHash("md5").update(primary).digest("hex").slice(0, 12);
  return path.join(ROOT_DATA_DIR, hash);
}

let mainPanel: vscode.WebviewView | undefined;
let pollTimer: ReturnType<typeof setInterval> | undefined;
let lastQuestionId: string | undefined;
let lastReplyTimestamp: string | undefined;
let lastQueueCount: number | undefined;
let chatTriggered = false;

function getMcpServerPath(): string {
  const extDir = path.dirname(path.dirname(__filename));
  return path.join(extDir, "dist", "mcp-server.mjs");
}

function getWorkspaceName(): string {
  const folders = vscode.workspace.workspaceFolders;
  return folders && folders.length > 0 ? folders[0].name : "default";
}

function getWorkspacePath(): string | undefined {
  const folders = vscode.workspace.workspaceFolders;
  return folders && folders.length > 0 ? folders[0].uri.fsPath : undefined;
}

/** 复制到当前数据目录 uploads，返回新路径，供 MCP 安全读取。 */
async function copyToUploads(sourcePath: string): Promise<string | null> {
  try {
    const uploadsDir = path.join(getDataDir(), "uploads");
    if (!fs.existsSync(uploadsDir)) fs.mkdirSync(uploadsDir, { recursive: true });
    const ext = path.extname(sourcePath) || "";
    const destPath = path.join(uploadsDir, makeId() + ext);
    fs.copyFileSync(sourcePath, destPath);
    return destPath;
  } catch {
    return null;
  }
}

function isValidAnswerData(data: unknown): data is AnswerData {
  if (!data || typeof data !== "object") return false;
  const o = data as Record<string, unknown>;
  return typeof o.id === "string" && Array.isArray(o.answers);
}

/** 检查全局是否已有本扩展的 MCP 配置（~/.cursor/mcp.json，Win/Mac 通用）。 */
function hasMcpConfigGlobal(): boolean {
  if (!fs.existsSync(GLOBAL_MCP_JSON)) return false;
  try {
    const config = JSON.parse(fs.readFileSync(GLOBAL_MCP_JSON, "utf-8")) as { mcpServers?: Record<string, unknown> };
    return Boolean(config.mcpServers?.[MCP_DISPLAY_NAME]);
  } catch {
    return false;
  }
}

/** 检查指定工作区是否已有本扩展的 MCP 配置。 */
function hasMcpConfig(workspaceFolder: string): boolean {
  const mcpJsonPath = path.join(workspaceFolder, ".cursor", "mcp.json");
  if (!fs.existsSync(mcpJsonPath)) return false;
  try {
    const config = JSON.parse(fs.readFileSync(mcpJsonPath, "utf-8")) as { mcpServers?: Record<string, unknown> };
    return Boolean(config.mcpServers?.[MCP_DISPLAY_NAME]);
  } catch {
    return false;
  }
}

/** 写入全局 MCP 配置（~/.cursor/mcp.json），使用 ROOT_DATA_DIR。 */
function setupMcpConfigGlobal(): boolean {
  if (!fs.existsSync(GLOBAL_CURSOR_DIR)) {
    fs.mkdirSync(GLOBAL_CURSOR_DIR, { recursive: true });
  }
  let config: { mcpServers?: Record<string, unknown> } = {};
  if (fs.existsSync(GLOBAL_MCP_JSON)) {
    try {
      config = JSON.parse(fs.readFileSync(GLOBAL_MCP_JSON, "utf-8"));
    } catch {
      // ignore
    }
  }
  if (!config.mcpServers) config.mcpServers = {};
  config.mcpServers[MCP_DISPLAY_NAME] = {
    command: "node",
    args: [getMcpServerPath()],
    env: { MESSENGER_DATA_DIR: ROOT_DATA_DIR },
  };
  const nextContent = JSON.stringify(config, null, 2);
  const previousContent = fs.existsSync(GLOBAL_MCP_JSON)
    ? fs.readFileSync(GLOBAL_MCP_JSON, "utf-8")
    : "";
  if (nextContent !== previousContent) {
    fs.writeFileSync(GLOBAL_MCP_JSON, nextContent, "utf-8");
    return true;
  }
  return false;
}

/** 写入全局规则（~/.cursor/rules/mcp-messenger.mdc）。 */
function setupCursorRulesGlobal(): boolean {
  if (!fs.existsSync(GLOBAL_RULES_DIR)) {
    fs.mkdirSync(GLOBAL_RULES_DIR, { recursive: true });
  }
  const rulesPath = path.join(GLOBAL_RULES_DIR, RULES_FILE_NAME);
  const previousContent = fs.existsSync(rulesPath) ? fs.readFileSync(rulesPath, "utf-8") : "";
  if (previousContent !== RULES_CONTENT) {
    fs.writeFileSync(rulesPath, RULES_CONTENT, "utf-8");
    return true;
  }
  return false;
}

/** 将规则写入所有打开的工作区的 .cursor/rules，确保 Cursor 能加载（Cursor 可能只读工作区规则）。 */
function ensureRulesInWorkspaces(workspaceFolders: readonly vscode.WorkspaceFolder[]): number {
  let count = 0;
  for (const folder of workspaceFolders) {
    const rulesDir = path.join(folder.uri.fsPath, ".cursor", "rules");
    if (!fs.existsSync(rulesDir)) fs.mkdirSync(rulesDir, { recursive: true });
    const rulesPath = path.join(rulesDir, RULES_FILE_NAME);
    if (!fs.existsSync(rulesPath) || fs.readFileSync(rulesPath, "utf-8") !== RULES_CONTENT) {
      fs.writeFileSync(rulesPath, RULES_CONTENT, "utf-8");
      count++;
    }
  }
  return count;
}

/** 在有工作区时，为首个工作区写入 .cursor/mcp.json 并使用该工作区独立数据目录，避免多窗口/多会话串消息。 */
function ensureMcpConfigInWorkspaces(workspaceFolders: readonly vscode.WorkspaceFolder[]): number {
  if (workspaceFolders.length === 0) return 0;
  const dataDir = computeDataDir(workspaceFolders);
  const firstFolder = workspaceFolders[0].uri.fsPath;
  const cursorDir = path.join(firstFolder, ".cursor");
  if (!fs.existsSync(cursorDir)) fs.mkdirSync(cursorDir, { recursive: true });
  const mcpJsonPath = path.join(cursorDir, "mcp.json");
  let config: { mcpServers?: Record<string, unknown> } = {};
  if (fs.existsSync(mcpJsonPath)) {
    try {
      config = JSON.parse(fs.readFileSync(mcpJsonPath, "utf-8"));
    } catch {
      // ignore
    }
  }
  if (!config.mcpServers) config.mcpServers = {};
  const entry = {
    command: "node",
    args: [getMcpServerPath()],
    env: { MESSENGER_DATA_DIR: dataDir },
  };
  const prevEntry = config.mcpServers[MCP_DISPLAY_NAME] as { env?: { MESSENGER_DATA_DIR?: string } } | undefined;
  if (prevEntry?.env?.MESSENGER_DATA_DIR === dataDir) return 0;
  config.mcpServers[MCP_DISPLAY_NAME] = entry;
  fs.writeFileSync(mcpJsonPath, JSON.stringify(config, null, 2), "utf-8");
  return 1;
}

/** 延迟后重新加载当前窗口，使 MCP/规则配置生效。 */
function reloadWindowAfterInstall(): void {
  vscode.window.showInformationMessage("MCP 配置已就绪，正在重新加载窗口…");
  setTimeout(() => {
    void vscode.commands.executeCommand("workbench.action.reloadWindow");
  }, 1500);
}

/** 从全局移除 MCP 配置。 */
function removeMcpConfigGlobal(): boolean {
  let removed = false;
  if (fs.existsSync(GLOBAL_MCP_JSON)) {
    try {
      const config = JSON.parse(fs.readFileSync(GLOBAL_MCP_JSON, "utf-8")) as { mcpServers?: Record<string, unknown> };
      if (config.mcpServers?.[MCP_DISPLAY_NAME]) {
        delete config.mcpServers[MCP_DISPLAY_NAME];
        fs.writeFileSync(GLOBAL_MCP_JSON, JSON.stringify(config, null, 2), "utf-8");
        removed = true;
      }
    } catch {
      // ignore
    }
  }
  const rulesPath = path.join(GLOBAL_RULES_DIR, RULES_FILE_NAME);
  if (fs.existsSync(rulesPath)) {
    try {
      fs.unlinkSync(rulesPath);
      removed = true;
    } catch {
      // ignore
    }
  }
  return removed;
}

/** 为指定工作区写入 MCP 配置；messengerDataDir 用于 env，使该窗口的 MCP 使用对应数据目录。 */
function setupMcpConfig(workspaceFolder: string, messengerDataDir: string): boolean {
  const cursorDir = path.join(workspaceFolder, ".cursor");
  if (!fs.existsSync(cursorDir)) {
    fs.mkdirSync(cursorDir, { recursive: true });
  }
  const mcpJsonPath = path.join(cursorDir, "mcp.json");
  let config: { mcpServers?: Record<string, unknown> } = {};
  if (fs.existsSync(mcpJsonPath)) {
    try {
      config = JSON.parse(fs.readFileSync(mcpJsonPath, "utf-8"));
    } catch {
      // ignore
    }
  }
  if (!config.mcpServers) config.mcpServers = {};
  config.mcpServers[MCP_DISPLAY_NAME] = {
    command: "node",
    args: [getMcpServerPath()],
    env: { MESSENGER_DATA_DIR: messengerDataDir },
  };
  const nextContent = JSON.stringify(config, null, 2);
  const previousContent = fs.existsSync(mcpJsonPath)
    ? fs.readFileSync(mcpJsonPath, "utf-8")
    : "";
  if (nextContent !== previousContent) {
    fs.writeFileSync(mcpJsonPath, nextContent, "utf-8");
    return true;
  }
  return false;
}

function setupCursorRules(workspaceFolder: string): boolean {
  const rulesDir = path.join(workspaceFolder, ".cursor", "rules");
  if (!fs.existsSync(rulesDir)) {
    fs.mkdirSync(rulesDir, { recursive: true });
  }
  const currentRulesPath = path.join(rulesDir, RULES_FILE_NAME);
  const previousContent = fs.existsSync(currentRulesPath)
    ? fs.readFileSync(currentRulesPath, "utf-8")
    : "";
  let changed = false;
  if (previousContent !== RULES_CONTENT) {
    fs.writeFileSync(currentRulesPath, RULES_CONTENT, "utf-8");
    changed = true;
  }
  const legacyPath = path.join(rulesDir, LEGACY_RULES_FILE_NAME);
  if (fs.existsSync(legacyPath)) {
    try {
      if (fs.readFileSync(legacyPath, "utf-8") === RULES_CONTENT) {
        fs.unlinkSync(legacyPath);
        changed = true;
      }
    } catch {
      // ignore
    }
  }
  return changed;
}

function removeMcpConfig(workspaceFolder: string): boolean {
  const mcpJsonPath = path.join(workspaceFolder, ".cursor", "mcp.json");
  let removed = false;
  if (fs.existsSync(mcpJsonPath)) {
    try {
      const config = JSON.parse(fs.readFileSync(mcpJsonPath, "utf-8"));
      if (config.mcpServers?.[MCP_DISPLAY_NAME]) {
        delete config.mcpServers[MCP_DISPLAY_NAME];
        fs.writeFileSync(mcpJsonPath, JSON.stringify(config, null, 2), "utf-8");
        removed = true;
      }
    } catch {
      // ignore
    }
  }
  if (removeCursorRules(workspaceFolder)) removed = true;
  return removed;
}

function removeCursorRules(workspaceFolder: string): boolean {
  const rulesDir = path.join(workspaceFolder, ".cursor", "rules");
  let removed = false;
  const currentPath = path.join(rulesDir, RULES_FILE_NAME);
  if (fs.existsSync(currentPath)) {
    fs.unlinkSync(currentPath);
    removed = true;
  }
  const legacyPath = path.join(rulesDir, LEGACY_RULES_FILE_NAME);
  if (fs.existsSync(legacyPath)) {
    try {
      if (fs.readFileSync(legacyPath, "utf-8") === RULES_CONTENT) {
        fs.unlinkSync(legacyPath);
        removed = true;
      }
    } catch {
      // ignore
    }
  }
  return removed;
}

async function triggerCursorChat(): Promise<void> {
  if (chatTriggered) return;
  chatTriggered = true;
  try {
    await vscode.commands.executeCommand("workbench.action.chat.newChat");
    await new Promise((r) => setTimeout(r, 500));
    await vscode.commands.executeCommand("workbench.action.chat.open", {
      query: "你好，请处理我的消息",
    });
  } catch {
    // ignore
  }
}

let pollTick = 0;

function startPolling(): void {
  const poll = () => {
    if (!mainPanel) return;
    const question = readQuestion();
    if (question) {
      if (question.id !== lastQuestionId) {
        mainPanel.webview.postMessage({
          type: "showQuestion",
          data: question,
        });
        lastQuestionId = question.id;
      }
    } else if (lastQuestionId) {
      mainPanel.webview.postMessage({ type: "clearQuestion" });
      lastQuestionId = undefined;
    }
    const reply = readReply();
    if (reply && reply.timestamp !== lastReplyTimestamp) {
      mainPanel.webview.postMessage({ type: "showReply", data: reply });
      lastReplyTimestamp = reply.timestamp;
    } else if (!reply) {
      lastReplyTimestamp = undefined;
    }
    const sid = getCurrentSessionId();
    const queue = readQueue(sid);
    const count = queue.length;
    pollTick += 1;
    const forceSync = pollTick % 4 === 0;
    if (count !== lastQueueCount || forceSync) {
      mainPanel.webview.postMessage({ type: "queueCount", count, queue });
      lastQueueCount = count;
    }
  };
  poll();
  pollTimer = setInterval(poll, 500);
}

function setupMcpForFolders(workspaceFolders: readonly vscode.WorkspaceFolder[]): number {
  if (workspaceFolders.length === 0) return 0;
  const dataDir = computeDataDir(workspaceFolders);
  setDataDir(dataDir);
  let changedCount = 0;
  for (const folder of workspaceFolders) {
    if (setupMcpConfig(folder.uri.fsPath, dataDir) || setupCursorRules(folder.uri.fsPath)) {
      changedCount++;
    }
  }
  return changedCount;
}

/** 检查全局或工作区是否有 MCP 配置；没有则自动安装到全局。激活时与工作区变更时调用。有工作区时始终写入工作区 mcp（按工作区隔离数据目录），避免多窗口串消息。 */
function autoSetupMcp(
  workspaceFolders: readonly vscode.WorkspaceFolder[] = vscode.workspace.workspaceFolders || []
): void {
  const hasGlobal = hasMcpConfigGlobal();
  const hasWorkspace = workspaceFolders.length > 0 && workspaceFolders.some((f) => hasMcpConfig(f.uri.fsPath));
  if (workspaceFolders.length > 0) {
    setDataDir(computeDataDir(workspaceFolders));
    ensureMcpConfigInWorkspaces(workspaceFolders);
    ensureRulesInWorkspaces(workspaceFolders);
    // 只保留工作区配置，从全局移除，避免 Cursor 列出两个「Cursor Messenger」
    removeMcpConfigGlobal();
    return;
  }
  if (hasGlobal || hasWorkspace) {
    setDataDir(ROOT_DATA_DIR);
    ensureRulesInWorkspaces(workspaceFolders);
    return;
  }
  setupMcpConfigGlobal();
  setupCursorRulesGlobal();
  setDataDir(ROOT_DATA_DIR);
  ensureRulesInWorkspaces(workspaceFolders);
  reloadWindowAfterInstall();
}

interface WebviewState {
  input?: string;
  history?: Array<{ text: string; time: string }>;
}

class MessengerViewProvider implements vscode.WebviewViewProvider {
  constructor(
    private readonly extensionUri: vscode.Uri,
    private readonly context: vscode.ExtensionContext
  ) {}

  resolveWebviewView(
    webviewView: vscode.WebviewView,
    _context: vscode.WebviewViewResolveContext,
    _token: vscode.CancellationToken
  ): void {
    mainPanel = webviewView;
    webviewView.webview.options = {
      enableScripts: true,
      localResourceRoots: [this.extensionUri],
    };
    webviewView.webview.html = this.getHtml(webviewView.webview);
    webviewView.webview.onDidReceiveMessage(async (msg: { type: string; text?: string; data?: unknown; dataUrl?: string; caption?: string; id?: string; input?: string; history?: Array<{ text: string; time: string }> }) => {
      switch (msg.type) {
        case "ready":
          this.pushCurrentState();
          break;
        case "saveState":
          this.context.globalState.update(WEBVIEW_STATE_KEY, {
            input: msg.input ?? "",
            history: msg.history ?? [],
          } as WebviewState);
          break;
        case "sendText":
          if (msg.text != null) {
            sendText(msg.text, getCurrentSessionId());
            triggerCursorChat();
          }
          break;
        case "sendImage":
          this.handleSendImage(msg.caption);
          break;
        case "sendPastedImage":
          if (msg.dataUrl != null) this.handlePastedImage(msg.dataUrl, msg.caption);
          break;
        case "sendFile":
          this.handleSendFile();
          break;
        case "submitAnswer":
          if (isValidAnswerData(msg.data)) writeAnswer(msg.data as AnswerData);
          break;
        case "cancelQuestion":
          cancelQuestion();
          break;
        case "ackReply":
          clearReply();
          break;
        case "deleteQueueItem":
          if (msg.id != null) deleteQueueItem(msg.id);
          break;
        case "fetchUsage":
          this.handleFetchUsage();
          break;
      }
    });
    webviewView.onDidDispose(() => {
      if (mainPanel === webviewView) {
        mainPanel = undefined;
        lastQuestionId = undefined;
        lastReplyTimestamp = undefined;
        lastQueueCount = undefined;
      }
    });
  }

  handlePastedImage(dataUrl: string, caption?: string): void {
    try {
      const match = dataUrl.match(/^data:image\/(\w+);base64,(.+)$/);
      if (!match) return;
      const ext = (match[1] === "jpeg" ? "jpg" : match[1]).toLowerCase().replace(/[^a-z0-9]/g, "") || "png";
      const buf = Buffer.from(match[2], "base64");
      const name = "cursor_mcp_" + Date.now() + "_" + Math.random().toString(36).slice(2, 8) + "." + ext;
      const tmpPath = path.join(os.tmpdir(), name);
      fs.writeFileSync(tmpPath, buf);
      sendImage(tmpPath, caption, getCurrentSessionId());
      triggerCursorChat();
    } catch {
      // ignore
    }
  }

  async handleSendImage(caption?: string): Promise<void> {
    const uris = await vscode.window.showOpenDialog({
      canSelectMany: false,
      filters: { Images: ["png", "jpg", "jpeg", "gif", "webp", "bmp", "svg"] },
    });
    if (!uris?.[0]) return;
    const copied = await copyToUploads(uris[0].fsPath);
    if (copied) sendImage(copied, caption, getCurrentSessionId());
  }

  async handleSendFile(): Promise<void> {
    const uris = await vscode.window.showOpenDialog({ canSelectMany: false });
    if (!uris?.[0]) return;
    const copied = await copyToUploads(uris[0].fsPath);
    if (copied) sendFile(copied, undefined, getCurrentSessionId());
  }

  pushCurrentState(): void {
    if (!mainPanel) return;
    const sid = getCurrentSessionId();
    const queue = readQueue(sid);
    mainPanel.webview.postMessage({ type: "queueCount", count: queue.length, queue });
    const saved = this.context.globalState.get<WebviewState>(WEBVIEW_STATE_KEY);
    mainPanel.webview.postMessage({
      type: "restoreState",
      input: saved?.input ?? "",
      history: Array.isArray(saved?.history) ? saved.history : [],
    });
  }

  async handleFetchUsage(): Promise<void> {
    if (!mainPanel) return;
    mainPanel.webview.postMessage({ type: "usageLoading" });
    try {
      const result = await fetchCursorUsage();
      mainPanel.webview.postMessage({ type: "usageData", data: result });
    } catch (e) {
      mainPanel.webview.postMessage({
        type: "usageData",
        data: { success: false, error: e instanceof Error ? e.message : "查询失败" },
      });
    }
  }

  private getHtml(webview: vscode.Webview): string {
    const scriptUri = webview.asWebviewUri(
      vscode.Uri.joinPath(this.extensionUri, "dist", "webview.js")
    );
    const styleUri = webview.asWebviewUri(
      vscode.Uri.joinPath(this.extensionUri, "dist", "webview.css")
    );
    return `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <link rel="stylesheet" href="${styleUri}">
</head>
<body>
  <div id="root"></div>
  <script src="${scriptUri}"></script>
</body>
</html>`;
  }
}

export function activate(context: vscode.ExtensionContext): void {
  const provider = new MessengerViewProvider(context.extensionUri, context);
  context.subscriptions.push(
    vscode.window.registerWebviewViewProvider(
      "cursorMcpMessenger.mainView",
      provider
    )
  );
  context.subscriptions.push(
    vscode.commands.registerCommand("cursorMcpMessenger.setupMcp", () => {
      const folders = vscode.workspace.workspaceFolders ?? [];
      let changed = false;
      if (folders.length > 0) {
        setDataDir(computeDataDir(folders));
        changed = ensureMcpConfigInWorkspaces(folders) > 0 || ensureRulesInWorkspaces(folders) > 0 || changed;
        if (removeMcpConfigGlobal()) changed = true;
      } else {
        setDataDir(ROOT_DATA_DIR);
        changed = setupMcpConfigGlobal() || setupCursorRulesGlobal();
      }
      if (changed) {
        reloadWindowAfterInstall();
      } else {
        vscode.window.showInformationMessage("MCP 配置已存在，无需重复安装");
      }
    })
  );
  context.subscriptions.push(
    vscode.commands.registerCommand("cursorMcpMessenger.removeMcp", () => {
      const removed = removeMcpConfigGlobal();
      vscode.window.showInformationMessage(
        removed ? "MCP 配置已从全局卸载" : "未发现可卸载的 MCP 配置"
      );
    })
  );
  context.subscriptions.push(
    vscode.commands.registerCommand(
      "cursorMcpMessenger.sendFile",
      (uri?: vscode.Uri) => {
        if (uri) {
          sendFile(uri.fsPath, undefined, getCurrentSessionId());
          vscode.window.showInformationMessage("文件已添加到消息队列");
        }
      }
    )
  );
  context.subscriptions.push(
    vscode.commands.registerCommand("cursorMcpMessenger.openConsole", () => {
      const port = getServerPort();
      if (!port) {
        vscode.window.showWarningMessage("控制台服务器尚未启动");
        return;
      }
      const url = `http://127.0.0.1:${port}`;
      void vscode.env.openExternal(vscode.Uri.parse(url));
    })
  );
  const folders = vscode.workspace.workspaceFolders ?? [];
  setWorkspaceInfo(getWorkspaceName(), getWorkspacePath());
  startLocalServer(
    () => ({
      queueCount: getQueueCount(getCurrentSessionId()),
      queue: readQueue(getCurrentSessionId()),
      question: readQuestion(),
      reply: readReply(),
      progress: readProgress(),
      workspace: { name: getWorkspaceName(), path: getWorkspacePath() },
      wsClients: getConnectedClients(),
      port: getServerPort(),
    }),
    {
      sendText: (text) => {
        sendText(text, getCurrentSessionId());
        triggerCursorChat();
      },
      writeAnswer: (data) => {
        if (isValidAnswerData(data)) writeAnswer(data as AnswerData);
      },
      cancelQuestion,
      clearReply,
    },
    0
  ).then((port) => {
    console.log(`Cursor Messenger 控制台已启动: http://127.0.0.1:${port}`);
  }).catch((e) => {
    console.error("启动控制台服务器失败:", e);
  });
  startPolling();
  autoSetupMcp(folders);
  context.subscriptions.push(
    vscode.workspace.onDidChangeWorkspaceFolders((event) => {
      const next = vscode.workspace.workspaceFolders ?? [];
      if (event.added.length > 0 || event.removed.length > 0) {
        setWorkspaceInfo(getWorkspaceName(), getWorkspacePath());
        autoSetupMcp(next);
        if (!hasMcpConfigGlobal()) {
          setDataDir(next.length > 0 ? computeDataDir(next) : ROOT_DATA_DIR);
        }
        lastQuestionId = undefined;
        lastReplyTimestamp = undefined;
        lastQueueCount = undefined;
        if (mainPanel) {
          const queue = readQueue(getCurrentSessionId());
          mainPanel.webview.postMessage({ type: "queueCount", count: queue.length, queue });
        }
      }
    })
  );
  context.subscriptions.push({
    dispose: () => {
      if (pollTimer) clearInterval(pollTimer);
    },
  });
}

export function deactivate(): void {
  if (pollTimer) clearInterval(pollTimer);
  stopLocalServer();
}
