/**
 * 与 xw-cursor-message 2.3.0 一致的额度查询：读取 Cursor 登录态，调用同一 API。
 */
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";
import * as https from "node:https";
import * as http from "node:http";
import { getDataDir } from "./messenger";

const API_BASE = process.env.MCP_API_BASE || "https://api.yidachuang.top/api";
const INJECTED_TOKEN_FILE = "injected-token.json";

function getCursorConfigDir(): string {
  switch (process.platform) {
    case "win32":
      return path.join(process.env.APPDATA || path.join(os.homedir(), "AppData", "Roaming"), "Cursor");
    case "darwin":
      return path.join(os.homedir(), "Library", "Application Support", "Cursor");
    default:
      return path.join(os.homedir(), ".config", "Cursor");
  }
}

function readVscdbViaSqlite(dbPath: string): { token: string; email: string } | null {
  try {
    const { DatabaseSync } = require("node:sqlite");
    const db = new DatabaseSync(dbPath, { readOnly: true });
    const tokenRow = db.prepare("SELECT value FROM ItemTable WHERE key = ?").get("cursorAuth/accessToken") as { value?: string } | undefined;
    const emailRow = db.prepare("SELECT value FROM ItemTable WHERE key = ?").get("cursorAuth/cachedEmail") as { value?: string } | undefined;
    db.close();
    if (tokenRow?.value) {
      return { token: tokenRow.value, email: emailRow?.value || "" };
    }
  } catch {
    // ignore
  }
  try {
    const { execSync } = require("child_process");
    const escaped = dbPath.replace(/\\/g, "\\\\").replace(/'/g, "\\'");
    const script = `const{DatabaseSync}=require("node:sqlite");const db=new DatabaseSync('${escaped}',{readOnly:true});const t=db.prepare("SELECT value FROM ItemTable WHERE key=?").get("cursorAuth/accessToken");const e=db.prepare("SELECT value FROM ItemTable WHERE key=?").get("cursorAuth/cachedEmail");db.close();console.log(JSON.stringify({t:t?.value||"",e:e?.value||""}))`;
    const out = execSync(`node --disable-warning=ExperimentalWarning -e "${script}"`, {
      encoding: "utf-8",
      timeout: 10000,
      windowsHide: true,
    }).trim();
    const parsed = JSON.parse(out) as { t?: string; e?: string };
    if (parsed.t) return { token: parsed.t, email: parsed.e || "" };
  } catch {
    // ignore
  }
  return null;
}

export function readCursorAuth(): { token: string; email: string } | null {
  const gsDir = path.join(getCursorConfigDir(), "User", "globalStorage");
  const dbPath = path.join(gsDir, "state.vscdb");
  if (fs.existsSync(dbPath)) {
    const result = readVscdbViaSqlite(dbPath);
    if (result) return result;
  }
  const jsonPath = path.join(gsDir, "storage.json");
  if (fs.existsSync(jsonPath)) {
    try {
      const data = JSON.parse(fs.readFileSync(jsonPath, "utf-8")) as Record<string, unknown>;
      const token = data["cursorAuth/accessToken"];
      if (typeof token === "string") {
        return { token, email: (data["cursorAuth/cachedEmail"] as string) || "" };
      }
    } catch {
      // ignore
    }
  }
  const authPath = path.join(gsDir, "cursor.auth.json");
  if (fs.existsSync(authPath)) {
    try {
      const data = JSON.parse(fs.readFileSync(authPath, "utf-8")) as { token?: string; email?: string };
      if (data.token) return { token: data.token, email: data.email || "" };
    } catch {
      // ignore
    }
  }
  return null;
}

function readInjectedToken(): { token: string } | null {
  const file = path.join(getDataDir(), INJECTED_TOKEN_FILE);
  if (!fs.existsSync(file)) return null;
  try {
    const data = JSON.parse(fs.readFileSync(file, "utf-8")) as { token?: string };
    return data?.token ? { token: data.token } : null;
  } catch {
    return null;
  }
}

function getEffectiveAuth(): { token: string; email: string } | null {
  const injected = readInjectedToken();
  if (injected) return { token: injected.token, email: "" };
  return readCursorAuth();
}

function apiRequest(endpoint: string, body: object): Promise<Record<string, unknown>> {
  return new Promise((resolve, reject) => {
    const url = new URL(API_BASE + endpoint);
    const isHttps = url.protocol === "https:";
    const postData = JSON.stringify(body);
    const options = {
      hostname: url.hostname,
      port: url.port || (isHttps ? 443 : 80),
      path: url.pathname + url.search,
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Content-Length": Buffer.byteLength(postData),
      },
    };
    const mod = isHttps ? https : http;
    const req = mod.request(options, (res) => {
      let data = "";
      res.on("data", (chunk: Buffer) => {
        data += chunk.toString();
      });
      res.on("end", () => {
        try {
          resolve(JSON.parse(data) as Record<string, unknown>);
        } catch {
          resolve({ error: data });
        }
      });
    });
    req.on("error", reject);
    req.setTimeout(15000, () => {
      req.destroy();
      reject(new Error("请求超时"));
    });
    req.write(postData);
    req.end();
  });
}

export interface UsageData {
  success: boolean;
  error?: string;
  email?: string;
  membershipType?: string;
  usagePct?: number | null;
  billingCycleStart?: string;
  billingCycleEnd?: string;
  totalCost?: number;
  eventsCount?: number;
  models?: Array<{ name?: string; count?: number; cost?: number }>;
}

export async function fetchCursorUsage(): Promise<UsageData> {
  const auth = getEffectiveAuth();
  if (!auth) {
    return { success: false, error: "未检测到 Cursor 登录信息" };
  }
  try {
    const resp = await apiRequest("/subscriptions/local-token-info", { token: auth.token }) as {
      success?: boolean;
      error?: string;
      data?: {
        email?: string;
        membershipType?: string;
        usagePct?: number;
        billingStart?: string;
        billingEnd?: string;
        totalCost?: number;
        eventsCount?: number;
        models?: Array<{ name?: string; count?: number; cost?: number }>;
      };
    };
    if (!resp || !resp.success) {
      return { success: false, error: (resp as { error?: string })?.error || "Token 已失效，请重新登录 Cursor" };
    }
    const d = resp.data;
    return {
      success: true,
      email: d?.email ?? auth.email,
      membershipType: d?.membershipType ?? "-",
      usagePct: d?.usagePct ?? null,
      billingCycleStart: d?.billingStart ?? "",
      billingCycleEnd: d?.billingEnd ?? "",
      totalCost: d?.totalCost ?? 0,
      eventsCount: d?.eventsCount ?? 0,
      models: d?.models ?? [],
    };
  } catch (e) {
    return {
      success: false,
      error: e instanceof Error ? e.message : "查询失败",
    };
  }
}
